+/// IMPL-28 / AG-O3: Unified fast-path gate bitfield.
+///
+/// Collapses the dozen-plus per-fast-path boolean checks into a single
+/// AND-tree so the innermost dispatch hot path can consult one atomic load
+/// instead of walking every independent flag. Each bit represents one
+/// precondition for the general fast lane; a consumer that needs ALL
+/// preconditions open can check equality against `ALL_GATES_OPEN` with
+/// one `Relaxed` load.
+///
+/// Safety/semantics: bits default CLOSED (0). A closed bit always means
+/// "take the slow/instrumented path", which is safe by construction. State
+/// transitions toggle bits on (opening the lane) only after the underlying
+/// invariant is re-established. This commit is ADDITIVE scaffolding — the
+/// gate is maintained but not yet consumed at dispatch sites. Follow-up
+/// commits migrate individual gate-site checks one at a time so semantic
+/// equivalence can be proven site-by-site.
+#[allow(dead_code)] // Consumed by follow-up migration commits; scaffolding only.
+pub(crate) mod fast_path_gate {
+    /// Explicit transaction is active (BEGIN without matching COMMIT/ROLLBACK).
+    pub const IN_TRANSACTION: u32 = 1 << 0;
+    /// Per-statement savepoint can be skipped in the current explicit txn.
+    pub const NO_STATEMENT_SAVEPOINT: u32 = 1 << 1;
+    /// Tracing subscribers are absent / disabled on this connection.
+    pub const TRACING_DISABLED: u32 = 1 << 2;
+    /// Schema cookie / schema_generation are stable (no DDL in flight).
+    pub const SCHEMA_STABLE: u32 = 1 << 3;
+
+    /// All preconditions open — the fully general fast lane is eligible.
+    pub const ALL_GATES_OPEN: u32 =
+        IN_TRANSACTION | NO_STATEMENT_SAVEPOINT | TRACING_DISABLED | SCHEMA_STABLE;
+}
