+    /// IMPL-28 / AG-O3: Toggle a single bit in the unified fast-path gate.
+    ///
+    /// `open=true` ORs the bit in; `open=false` masks it out. `Relaxed`
+    /// ordering is sufficient: the gate is a hint that must be re-verified
+    /// at the actual dispatch site if absolute freshness matters, and the
+    /// underlying invariants that gate the bit are already ordered by the
+    /// per-field store that established them (e.g. `in_transaction.set`).
+    #[inline]
+    pub(crate) fn set_fast_path_bit(&self, bit: u32, open: bool) {
+        if open {
+            self.fast_path_gate.fetch_or(bit, AtomicOrdering::Relaxed);
+        } else {
+            self.fast_path_gate.fetch_and(!bit, AtomicOrdering::Relaxed);
+        }
+    }
