+#[cfg(test)]
+mod fast_path_gate_tests {
+    //! IMPL-28 / AG-O3: scaffolding tests for the unified fast-path gate
+    //! bitfield. These tests only cover the newly-wired state-transition
+    //! hooks — they do NOT exercise dispatch-site consumers (migration of
+    //! those sites lands in follow-up commits).
+    use super::{Connection, fast_path_gate};
+
+    #[test]
+    fn initial_gate_has_no_bits_open() {
+        // Fresh connection must default to gate=0 so any unmigrated
+        // consumer of `fast_paths_enabled()` falls back to the slow path.
+        let conn = Connection::open(":memory:").unwrap();
+        assert_eq!(
+            conn.fast_path_gate_snapshot(),
+            0,
+            "fresh connection must have all gate bits closed"
+        );
+        assert!(
+            !conn.fast_paths_enabled(),
+            "fast_paths_enabled() must be false until every bit opens"
+        );
+    }
+
+    #[test]
+    fn begin_opens_in_transaction_bit_and_commit_clears_it() {
+        let conn = Connection::open(":memory:").unwrap();
+        let before = conn.fast_path_gate_snapshot();
+        assert_eq!(before & fast_path_gate::IN_TRANSACTION, 0);
+
+        conn.execute("BEGIN").unwrap();
+        let during = conn.fast_path_gate_snapshot();
+        assert_eq!(
+            during & fast_path_gate::IN_TRANSACTION,
+            fast_path_gate::IN_TRANSACTION,
+            "BEGIN must open IN_TRANSACTION bit"
+        );
+
+        conn.execute("COMMIT").unwrap();
+        let after = conn.fast_path_gate_snapshot();
+        assert_eq!(
+            after & fast_path_gate::IN_TRANSACTION,
+            0,
+            "COMMIT must clear IN_TRANSACTION bit"
+        );
+    }
+
+    #[test]
+    fn rollback_clears_in_transaction_bit() {
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute("BEGIN").unwrap();
+        assert_ne!(
+            conn.fast_path_gate_snapshot() & fast_path_gate::IN_TRANSACTION,
+            0
+        );
+        conn.execute("ROLLBACK").unwrap();
+        assert_eq!(
+            conn.fast_path_gate_snapshot() & fast_path_gate::IN_TRANSACTION,
+            0,
+            "ROLLBACK must clear IN_TRANSACTION bit"
+        );
+    }
+
+    #[test]
+    fn ddl_toggles_schema_stable_and_leaves_it_open_on_completion() {
+        let conn = Connection::open(":memory:").unwrap();
+        // CREATE TABLE runs increment_schema_cookie which closes
+        // SCHEMA_STABLE mid-op and reopens it at the end.
+        conn.execute("CREATE TABLE t (a INTEGER);").unwrap();
+        assert_ne!(
+            conn.fast_path_gate_snapshot() & fast_path_gate::SCHEMA_STABLE,
+            0,
+            "after DDL settles, SCHEMA_STABLE must be reopened"
+        );
+    }
+
+    #[test]
+    fn set_fast_path_bit_helper_roundtrip() {
+        let conn = Connection::open(":memory:").unwrap();
+        conn.set_fast_path_bit(fast_path_gate::TRACING_DISABLED, true);
+        assert_ne!(
+            conn.fast_path_gate_snapshot() & fast_path_gate::TRACING_DISABLED,
+            0
+        );
+        conn.set_fast_path_bit(fast_path_gate::TRACING_DISABLED, false);
+        assert_eq!(
+            conn.fast_path_gate_snapshot() & fast_path_gate::TRACING_DISABLED,
+            0
+        );
+    }
+
+    #[test]
+    fn all_gates_open_requires_every_bit() {
+        // Sanity check on the composite constant itself: its bit width
+        // must match the sum of the individual bits.
+        let expected = fast_path_gate::IN_TRANSACTION
+            | fast_path_gate::NO_STATEMENT_SAVEPOINT
+            | fast_path_gate::TRACING_DISABLED
+            | fast_path_gate::SCHEMA_STABLE;
+        assert_eq!(fast_path_gate::ALL_GATES_OPEN, expected);
+    }
+}
